import React from 'react';
import '../styles/Dashboard.css';

// Same image logic as ProgramAvatar
const AVATAR_IMAGES = {
  base: {
    s1: '/Avatars/sittingavatar.jpg',
    s2: '/Avatars/skin-brown.png',
  },
  skinArmour: {
    s2_ar2: '/Avatars/skin-brown-iron.png',
    s2_ar3: '/Avatars/skin-brown-mage.png',
    s2_ar4: '/Avatars/skin-brown-gold.png',
    s2_ar5: '/Avatars/skin-brown-shadow.png',
    s2_ar6: '/Avatars/skin-brown-dragon.png',
  },
  armour: {
    ar1: null,
    ar2: '/Avatars/armour-iron.png',
    ar3: '/Avatars/purple-armour.png',
    ar4: '/Avatars/gold-armour.png',
    ar5: '/Avatars/armour-shadow.png',
    ar6: '/Avatars/red-armour.png',
  },
};

const getAvatarImage = (selections) => {
  if (!selections) return '/Avatars/sittingavatar.jpg';
  const skin   = selections.skin   || 's1';
  const armour = selections.armour || 'ar1';

  const skinArmourImg = AVATAR_IMAGES.skinArmour[`${skin}_${armour}`];
  if (skinArmourImg) return skinArmourImg;

  const armourImg = skin === 's1' ? AVATAR_IMAGES.armour[armour] : null;
  if (armourImg) return armourImg;

  return AVATAR_IMAGES.base[skin] || '/Avatars/sittingavatar.jpg';
};

const Dashboard = ({ avatarSelections, avatarName }) => {
  const avatarImg = getAvatarImage(avatarSelections);

  return (
    <div className="page-container">
      <div className="dashboard-grid">

        {/* Avatar and Stats Section */}
        <div className="card large-card">
          <div className="avatar-section">
            <div className="avatar-circle" data-testid="avatar-image">
              <img
                src={avatarImg}
                alt={avatarName || 'My Avatar'}
                className="avatar-circle-img"
                onError={(e) => { e.target.src = '/Avatars/sittingavatar.jpg'; }}
              />
              {avatarName && (
                <span className="avatar-circle-name">{avatarName}</span>
              )}
            </div>
            <div className="stat-bars">
              <div className="stat-bar" data-testid="hp-bar">
                <span className="stat-icon">❤️</span>
                <div className="progress-bar">
                  <div className="progress-fill red" style={{width: '65%'}}></div>
                </div>
                <span className="stat-label">HP</span>
              </div>
              <div className="stat-bar" data-testid="energy-bar">
                <span className="stat-icon">⚡</span>
                <div className="progress-bar">
                  <div className="progress-fill blue" style={{width: '80%'}}></div>
                </div>
                <span className="stat-label">Energy</span>
              </div>
              <div className="stat-bar" data-testid="discipline-bar">
                <span className="stat-icon">💪</span>
                <div className="progress-bar">
                  <div className="progress-fill green" style={{width: '45%'}}></div>
                </div>
                <span className="stat-label">Discipline</span>
              </div>
            </div>
          </div>
        </div>

        {/* Heart Rate Card */}
        <div className="card small-card" data-testid="heart-rate-card">
          <h3>Heart Rate</h3>
          <div className="heart-icon">❤️</div>
          <div className="heart-rate-value">{/* Content to be added */}</div>
        </div>

        {/* Sleep Card */}
        <div className="card small-card" data-testid="sleep-card">
          <h3>Sleep</h3>
          <div className="sleep-chart">{/* Content to be added */}</div>
        </div>

        {/* Steps Card */}
        <div className="card small-card" data-testid="steps-card">
          <h3>Steps</h3>
          <div className="steps-content">{/* Content to be added */}</div>
        </div>

        {/* Calories Card */}
        <div className="card small-card" data-testid="calories-card">
          <h3>Calories</h3>
          <div className="calories-chart">{/* Content to be added */}</div>
        </div>

        {/* Challenges Card */}
        <div className="card medium-card" data-testid="challenges-summary-card">
          <h3>Challenges</h3>
          <div className="challenge-list">{/* Content to be added */}</div>
        </div>

        {/* Stress Card */}
        <div className="card medium-card" data-testid="stress-card">
          <h3>Stress</h3>
          <div className="stress-meter">{/* Content to be added */}</div>
        </div>

        {/* Action Buttons */}
        <button className="dashboard-action-btn log-btn" data-testid="log-activities-btn">
          Log Activities and Food Intake
        </button>
        <button className="dashboard-action-btn sync-btn" data-testid="sync-device-btn">
          Sync Device
        </button>

      </div>
    </div>
  );
};

export default Dashboard;
